function serialiseMaze(env){return env.base.map((row,y)=>row.map((base,x)=>{if(base==='#')return '#';const key=cellKey(x,y);if(key===cellKey(...env.player))return '@';if(key===cellKey(...env.goal))return '.';return ' ';}).join('')).join('\n');}
