  const response=await fetch('https://api.anthropic.com/v1/messages',{method:'POST',headers:{'content-type':'application/json','x-api-key':key,'anthropic-version':'2023-06-01'},body:JSON.stringify({model,max_tokens:140,system:`You are a focused ${kind} exploration subagent. Return ONLY valid JSON with exactly these short string fields: {"finding":"one board-grounded conclusion","next":"one concrete recommendation","confidence":"low, medium, or high"}. Do not include a board map, coordinate transcript, chain-of-thought, Markdown, or preamble. If uncertain, say so in finding.`,messages:[{role:'user',content:`Question: ${String(task||'Assess one distinct strategy.').slice(0,700)}\n\nBoard:\n${board}`}],...thinkingConfigFor(model)})});
  const body=await response.json(),report=conciseExplorerReport((body.content||[]).filter(item=>item.type==='text').map(item=>item.text||'').join(''));return response.ok?{ok:true,report,usage:usageFrom(body)}:{ok:false,report:`Explorer could not run: ${providerError(body,response.status,model)}`,usage:usageFrom(body)};
