function runAnthropicSokobanAgent({map,model,onEvent,task,solverMode}){const env=parseSokoban(map);return runAnthropicStructuredAgent({kind:'Sokoban',env,serialise:serialiseSokoban,apply:applySokoban,solve:solveSokoban,isSolved:state=>state.goals.every(goal=>crateIndex(state,...goal)>=0),model,onEvent,task,solverMode});}
