function serialiseVisualKlotski(env){const pieces=env.pieces.map((piece,index)=>{const tone=piece.tone||['gold','coral','mint','violet'][index%4],shape=piece.w>piece.h?`horizontal ${piece.w}-cell block`:`vertical ${piece.h}-cell block`;return`${tone} ${shape}: center (${(piece.x+piece.w/2)*100}, ${(piece.y+piece.h/2)*100})`}).join('; ');return`Virtual screen: ${env.cols*100} × ${env.rows*100}. Board coordinates begin at the top-left. Exit: right edge of row ${env.exitRow+1}. Visible pieces: ${pieces}. Cursor: (${env.cursor.x}, ${env.cursor.y}). Use mouse_drag from inside a coloured block to a destination along its long axis.`;}
