function jigsawGeometry(n){const trayRows=Math.ceil((n*n)/4);return{width:1000,height:Math.max(760,350+trayRows*82),board:{x:20,y:40,size:600},tray:{x:670,y:330,size:68,gap:12,cols:4}}}
