function jigsawTileAt(env,point){const geometry=jigsawGeometry(env.n),tray=geometry.tray,column=Math.floor((point.x-tray.x)/(tray.size+tray.gap)),row=Math.floor((point.y-tray.y)/(tray.size+tray.gap)),withinX=(point.x-tray.x)%(tray.size+tray.gap),withinY=(point.y-tray.y)%(tray.size+tray.gap);if(column<0||column>=tray.cols||row<0||withinX>tray.size||withinY>tray.size)return null;return env.remaining[row*tray.cols+column]??null;}
