  const emit=event=>{try{onEvent?.(event)}catch{}};const record=(label,text,meta={})=>{const entry={label,text,...meta};traces.push(entry);emit({type:'trace',entry});};const pointSchema={type:'object',properties:{x:{type:'number',minimum:0},y:{type:'number',minimum:0}},required:['x','y']};
